BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?signal ?name ?owner ?ownerName WHERE {
  ?signal rdf:type vocab:signal .
  ?signal vocab:NamedElement_name ?name .
  OPTIONAL { 
    ?signal vocab:Element_owner ?owner .
    ?owner vocab:NamedElement_name ?ownerName .
  }
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("PEAS-"))) 
}
LIMIT 50
